    pub fn handle_trades(&self, mut client: Value, mut message: Value) {
        //
        //    {
        //        "Channel": "ticker-btc-usd",
        //        "Nonce": 130,
        //        "Data": {
        //          "TradeGuid": "7a669f2a-d564-472b-8493-6ef982eb1e96",
        //          "Pair": "btc-aud",
        //          "TradeDate": "2023-02-12T10:04:13.0804889+11:00",
        //          "Price": 31640,
        //          "Volume": 0.00079029,
        //          "BidGuid": "ba8a78b5-be69-4d33-92bb-9df0daa6314e",
        //          "OfferGuid": "27d20270-f21f-4c25-9905-152e70b2f6ec",
        //          "Side": "Buy"
        //        },
        //        "Time": 1676156653111,
        //        "Event": "Trade"
        //    }
        //
        let mut data: Value = self.safe_value_k(message.clone(), "Data", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut marketId: Value = self.safe_string_k(data.clone(), "Pair", &[]);
        let mut symbol: Value = self.safe_symbol(marketId.clone(), &[Value::Null, Value::Str("-".to_string())]);
        let mut messageHash: Value = add(&Value::Str("trades:".to_string()), &symbol);
        let mut stored: Value = self.safe_value(self.trades.clone(), symbol.clone(), &[]);
        if is_equal(&stored, &Value::Null) {
            let mut limit: Value = self.safe_integer_k(self.options.clone(), "tradesLimit", &[Value::Int(1000)]);
            stored = ArrayCache::new(limit.clone());
            add_element_to_object(&mut self.trades.clone(), &symbol, stored.clone());
        }
        let mut trade: Value = self.parse_ws_trade(data.clone(), &[]);
        stored.append(trade.clone());
        add_element_to_object(&mut self.trades.clone(), &symbol, stored.clone());
        client.resolve(&[get_value(&self.trades, &symbol), messageHash.clone()]);
}

